PREFIX dcterms: <http://purl.org/dc/terms/>
PREFIX lexinfo: <http://www.lexinfo.net/ontology/3.0/lexinfo#>
PREFIX ontolex: <http://www.w3.org/ns/lemon/ontolex#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX skos: <http://www.w3.org/2004/02/skos/core#>
PREFIX vartrans: <http://www.w3.org/ns/lemon/vartrans#>

SELECT ?itLemmaString ?sicWR
WHERE {
  SERVICE <https://klab.ilc.cnr.it/graphdb-compl-it/> {
    ?seedWord a ontolex:Word ;
              lexinfo:partOfSpeech [ rdfs:label ?posLabel ] ;
              ontolex:canonicalForm [ ontolex:writtenRep ?seedForm ] ;
              ontolex:sense ?seedSense .

    FILTER(str(?seedForm) = "donna") .
    ?senseRel lexinfo:hyponym ?seedSense .
    OPTIONAL { ?senseRel skos:definition ?definition . }
    ?wordRel ontolex:sense ?senseRel ;
             ontolex:canonicalForm ?formRel .
    ?formRel ontolex:writtenRep ?itLemmaString .

  }
  ?wordRel ontolex:canonicalForm ?liitaLemma .
  ?itToSicEntry ontolex:canonicalForm ?liitaLemma ;
               vartrans:translatableAs ?sicEntry .
  ?sicEntry ontolex:canonicalForm ?sicLemma .
  ?sicLemma dcterms:isPartOf <http://liita.it/data/id/DialettoSiciliano/lemma/LemmaBank> ;
           ontolex:writtenRep ?sicWR .
}
ORDER BY ?itLemmaString

PREFIX dcterms: <http://purl.org/dc/terms/>
PREFIX lila: <http://lila-erc.eu/ontologies/lila/>
PREFIX ontolex: <http://www.w3.org/ns/lemon/ontolex#>
PREFIX vartrans: <http://www.w3.org/ns/lemon/vartrans#>

SELECT ?wr ?parLemma ?parWR
WHERE {
  GRAPH <http://liita.it/data> {
    ?lemma a lila:Lemma .

    ?lemma ontolex:writtenRep ?wr .
    FILTER(STR(?wr) = "pane") .
  }
  BIND(?lemma AS ?liitaLemma)
  ?itToParEntry ontolex:canonicalForm ?liitaLemma ;
               vartrans:translatableAs ?parEntry .
  ?parEntry ontolex:canonicalForm ?parLemma .
  ?parLemma dcterms:isPartOf <http://liita.it/data/id/DialettoParmigiano/lemma/LemmaBank> ;
           ontolex:writtenRep ?parWR .
}

PREFIX ontolex: <http://www.w3.org/ns/lemon/ontolex#>

SELECT (COUNT(DISTINCT ?sense) AS ?count)
WHERE {
  SERVICE <https://klab.ilc.cnr.it/graphdb-compl-it/> {
    ?word ontolex:canonicalForm [ ontolex:writtenRep ?writtenRep ] ;
          ontolex:sense ?sense .
    FILTER(STR(?writtenRep) = "banco") .
  }
}

PREFIX ontolex: <http://www.w3.org/ns/lemon/ontolex#>

SELECT (COUNT(DISTINCT ?lemma) AS ?count)
WHERE {
  SERVICE <https://klab.ilc.cnr.it/graphdb-compl-it/> {
    ?word ontolex:canonicalForm [ ontolex:writtenRep ?writtenRep ] ;
          ontolex:sense ?sense .
    FILTER(STR(?writtenRep) = "campo") .
  }
}

PREFIX ontolex: <http://www.w3.org/ns/lemon/ontolex#>

SELECT ?writtenRep (COUNT(DISTINCT ?lemma) AS ?count)
WHERE {
  SERVICE <https://klab.ilc.cnr.it/graphdb-compl-it/> {
    ?word ontolex:canonicalForm [ ontolex:writtenRep ?writtenRep ] ;
          ontolex:sense ?sense .
    FILTER(STR(?writtenRep) = "punto") .
  }
}
GROUP BY ?writtenRep
ORDER BY DESC(?count)

PREFIX ontolex: <http://www.w3.org/ns/lemon/ontolex#>

SELECT (COUNT(DISTINCT ?sense) AS ?count)
WHERE {
  SERVICE <https://klab.ilc.cnr.it/graphdb-compl-it/> {
    ?word ontolex:canonicalForm [ ontolex:writtenRep ?writtenRep ] ;
          ontolex:sense ?sense .
    FILTER(STR(?writtenRep) = "capo") .
  }
}

PREFIX ontolex: <http://www.w3.org/ns/lemon/ontolex#>

SELECT ?writtenRep (COUNT(DISTINCT ?lemma) AS ?count)
WHERE {
  SERVICE <https://klab.ilc.cnr.it/graphdb-compl-it/> {
    ?word ontolex:canonicalForm [ ontolex:writtenRep ?writtenRep ] ;
          ontolex:sense ?sense .
    FILTER(STR(?writtenRep) = "fine") .
  }
}
GROUP BY ?writtenRep
ORDER BY DESC(?count)

PREFIX ontolex: <http://www.w3.org/ns/lemon/ontolex#>

SELECT ?writtenRep (COUNT(DISTINCT ?sense) AS ?count)
WHERE {
  SERVICE <https://klab.ilc.cnr.it/graphdb-compl-it/> {
    ?lexicalEntry ontolex:canonicalForm [ ontolex:writtenRep ?writtenRep ] .
    ?lexicalEntry ontolex:sense ?sense .
    FILTER(regex(str(?writtenRep), "^(banco|piano|campo|punto)$", "i")) .
  }
}
GROUP BY ?writtenRep
ORDER BY DESC(?count)

PREFIX ontolex: <http://www.w3.org/ns/lemon/ontolex#>

SELECT ?writtenRep (COUNT(DISTINCT ?sense) AS ?count)
WHERE {
  SERVICE <https://klab.ilc.cnr.it/graphdb-compl-it/> {
    ?lexicalEntry ontolex:canonicalForm [ ontolex:writtenRep ?writtenRep ] .
    ?lexicalEntry ontolex:sense ?sense .
    FILTER(regex(str(?writtenRep), "^(capo|fine|corso)$", "i")) .
  }
}
GROUP BY ?writtenRep
ORDER BY DESC(?count)

